import 'package:equatable/equatable.dart'; import '../../../../core/utils/date_parser.dart'; import '../../../../core/utils/enum_parser.dart'; import '../../../../core/utils/map_utils.dart';
enum ReportReason{scam,fakeProduct,inappropriateContent,harassment,spam,prohibitedItem,wrongCategory,other} enum ReportStatus{pending,reviewing,resolved,rejected} enum ReportTargetType{product,user,chat,review}
class Report extends Equatable{final String id,reporterId,targetId,description; final ReportTargetType targetType; final ReportReason reason; final ReportStatus status; final List<String> evidenceImageUrls; final String? adminNote,reviewedBy; final DateTime createdAt,updatedAt; final DateTime? reviewedAt; const Report({required this.id,required this.reporterId,required this.targetId,required this.targetType,required this.reason,this.status=ReportStatus.pending,required this.description,this.evidenceImageUrls=const[],this.adminNote,this.reviewedBy,required this.createdAt,required this.updatedAt,this.reviewedAt}); factory Report.fromMap(String id,Map<String,dynamic> map)=>Report(id:id,reporterId:MapUtils.stringValue(map,'reporterId'),targetId:MapUtils.stringValue(map,'targetId'),targetType:EnumParser.fromName(values:ReportTargetType.values,name:map['targetType'] as String?,fallback:ReportTargetType.product),reason:EnumParser.fromName(values:ReportReason.values,name:map['reason'] as String?,fallback:ReportReason.other),status:EnumParser.fromName(values:ReportStatus.values,name:map['status'] as String?,fallback:ReportStatus.pending),description:MapUtils.stringValue(map,'description'),evidenceImageUrls:MapUtils.stringListValue(map,'evidenceImageUrls'),adminNote:map['adminNote'] as String?,reviewedBy:map['reviewedBy'] as String?,createdAt:DateParser.fromValue(map['createdAt'])??DateTime.now(),updatedAt:DateParser.fromValue(map['updatedAt'])??DateTime.now(),reviewedAt:DateParser.fromValue(map['reviewedAt'])); Map<String,dynamic> toMap()=>{'reporterId':reporterId,'targetId':targetId,'targetType':targetType.name,'reason':reason.name,'status':status.name,'description':description,'evidenceImageUrls':evidenceImageUrls,'adminNote':adminNote,'reviewedBy':reviewedBy,'createdAt':createdAt.toIso8601String(),'updatedAt':updatedAt.toIso8601String(),'reviewedAt':reviewedAt?.toIso8601String()}; @override List<Object?> get props=>[id,reporterId,targetId,targetType,reason,status,description,evidenceImageUrls,adminNote,reviewedBy,createdAt,updatedAt,reviewedAt];}
